## protocol.py

```python
"""
Message protocol definitions.

All messages are JSON with the following envelope:
{
    "type": "<message_type>",
    "payload": { ... },
    "timestamp": "<ISO 8601>",       // set by server for outbound
    "id": "<uuid>"                    // set by server for outbound
}

Client -> Server types:
    - identify:  { "username": "..." }
    - join:      { "room": "..." }
    - leave:     { "room": "..." }
    - message:   { "room": "...", "content": "..." }
    - ping:      {}

Server -> Client types:
    - welcome:       { "username": "...", "server_time": "..." }
    - joined:        { "room": "...", "users": [...] }
    - left:          { "room": "..." }
    - message:       { "room": "...", "username": "...", "content": "..." }
    - system:        { "room": "...", "content": "..." }
    - history:       { "room": "...", "messages": [...] }
    - error:         { "code": "...", "message": "..." }
    - pong:          {}
    - user_joined:   { "room": "...", "username": "..." }
    - user_left:     { "room": "...", "username": "..." }
"""

import json
import uuid
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Optional

from exceptions import MalformedMessageError


class ClientMessageType(str, Enum):
    IDENTIFY = "identify"
    JOIN = "join"
    LEAVE = "leave"
    MESSAGE = "message"
    PING = "ping"


class ServerMessageType(str, Enum):
    WELCOME = "welcome"
    JOINED = "joined"
    LEFT = "left"
    MESSAGE = "message"
    SYSTEM = "system"
    HISTORY = "history"
    ERROR = "error"
    PONG = "pong"
    USER_JOINED = "user_joined"
    USER_LEFT = "user_left"


# Required payload fields per client message type
_REQUIRED_FIELDS: dict[ClientMessageType, list[str]] = {
    ClientMessageType.IDENTIFY: ["username"],
    ClientMessageType.JOIN: ["room"],
    ClientMessageType.LEAVE: ["room"],
    ClientMessageType.MESSAGE: ["room", "content"],
    ClientMessageType.PING: [],
}


def parse_client_message(raw: str | bytes) -> tuple[ClientMessageType, dict[str, Any]]:
    """
    Parse and validate a raw client message.

    Returns (message_type, payload) on success.
    Raises MalformedMessageError on any validation failure.
    """
    # --- Decode ---
    if isinstance(raw, bytes):
        try:
            raw = raw.decode("utf-8")
        except UnicodeDecodeError as exc:
            raise MalformedMessageError("Message is not valid UTF-8") from exc

    # --- JSON parse ---
    try:
        data = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise MalformedMessageError(f"Invalid JSON: {exc}") from exc

    if not isinstance(data, dict):
        raise MalformedMessageError("Message must be a JSON object")

    # --- Type field ---
    msg_type_raw = data.get("type")
    if msg_type_raw is None:
        raise MalformedMessageError("Missing 'type' field")

    try:
        msg_type = ClientMessageType(msg_type_raw)
    except ValueError as exc:
        raise MalformedMessageError(f"Unknown message type: {msg_type_raw!r}") from exc

    # --- Payload ---
    payload = data.get("payload")
    if payload is None:
        payload = {}
    if not isinstance(payload, dict):
        raise MalformedMessageError("'payload' must be a JSON object")

    # --- Required fields ---
    for field in _REQUIRED_FIELDS.get(msg_type, []):
        if field not in payload:
            raise MalformedMessageError(
                f"Missing required field '{field}' for type '{msg_type.value}'"
            )
        if not isinstance(payload[field], str):
            raise MalformedMessageError(
                f"Field '{field}' must be a string"
            )

    return msg_type, payload


def build_server_message(
    msg_type: ServerMessageType,
    payload: dict[str, Any],
    msg_id: Optional[str] = None,
) -> str:
    """Build a JSON-encoded server message."""
    message = {
        "type": msg_type.value,
        "payload": payload,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "id": msg_id or str(uuid.uuid4()),
    }
    return json.dumps(message, ensure_ascii=False)


def build_error_message(code: str, message: str) -> str:
    """Convenience: build an error response."""
    return build_server_message(
        ServerMessageType.ERROR,
        {"code": code, "message": message},
    )
